import com.evolveum.midpoint.xml.ns._public.common.common_3.*;
import com.evolveum.midpoint.prism.delta.*;
import com.evolveum.midpoint.schema.constants.SchemaConstants;
import javax.xml.namespace.QName;

def SCIBACK_NS = 'urn:sciback:midpoint:person';
def user = input;
def uoid = user.getOid();
def uname = user.getName()?.getOrig();

// OIDs structural por afiliación (los derivables de liveAffiliation)
def OID_FACULTY = 'c93083ca-f4c5-4704-acf4-d53b97c9556e';
def OID_STAFF   = '6460facf-3abf-4851-966e-0c95aa1a6c46';
def OID_STUDENT = '3037fbd2-db02-4ffd-8b1a-83fab5e686aa';
def OID_ALUM    = '87552943-9600-493b-88ca-74b7d3ba93e4';
// structural que NO se derivan de liveAffiliation (se conservan si son únicos)
// NOTA (2026-06-20): archetype-user-affiliate-researcher (ce162f6b) removido del set —
// el archetype se eliminó junto con todo el stack de investigación (MidPoint ya NO gobierna
// investigación; la aprovisiona el producto SciBack Research Project).
def OTHER_STRUCT = ['c5cdc4b5-e14f-4b2f-b65e-0a3fee8f6bde', // visitor
                    '18337126-27ad-421b-8860-59403c36f1b8', // contractor
                    '8f32f406-0d3d-4607-8406-9f1c494ab5fe', // partner-institution
                    '05ceed56-9a60-4531-903f-c7748b36de8a'] as Set; // service-account
def ALL_STRUCT = ([OID_FACULTY, OID_STAFF, OID_STUDENT, OID_ALUM] + (OTHER_STRUCT as List)) as Set;

// 1) Calcular afiliación VIVA desde la REALIDAD (shadows linked) — NO desde los items persistidos
//    (que pueden estar sin materializar antes del reconcile → race H2). Reality-vs-Policy §2.1:
//    la realidad son las proyecciones LAMB; el item es derivado. Aquí leemos la realidad directa.
//    IIA resources: Trabajadores ...e21 / Estudiantes ...e22 / Egresados ...e23.
def RES_WORKER  = '6a91f7e1-1b50-4dcf-9c4b-7c0c0e0e0e21';
def RES_STUDENT = '6a91f7e1-1b50-4dcf-9c4b-7c0c0e0e0e22';
def RES_ALUM    = '6a91f7e1-1b50-4dcf-9c4b-7c0c0e0e0e23';

def workerLive = false; def workerFaculty = false; def studentLive = false; def alumLive = false;
try {
    user.getLinkRef().each { lr ->
        def soid = lr.getOid();
        if (soid == null) return;
        def sh = midpoint.getObject(com.evolveum.midpoint.xml.ns._public.common.common_3.ShadowType.class, soid);
        if (sh == null) return;
        if (Boolean.TRUE.equals(sh.isDead())) return;  // proyección muerta NO cuenta
        def rOid = sh.getResourceRef()?.getOid();
        if (rOid == RES_ALUM) { alumLive = true; }
        else if (rOid == RES_STUDENT) { studentLive = true; }
        else if (rOid == RES_WORKER) {
            // worker vivo solo si ESTADO != 'I' (replica archetype-to-liveAffiliationWorker)
            def estado = null;
            try { estado = basic.getAttributeValue(sh, 'ESTADO'); } catch (Exception ee) {}
            if (!('I' == estado)) {
                workerLive = true;
                // faculty vs staff: por el archetype structural employee-faculty ya asignado
                workerFaculty = user.getAssignment().any { a -> a.getTargetRef()?.getOid() == OID_FACULTY };
            }
        }
    }
} catch (Exception e) { log.warn('SANEO: error leyendo shadows de {}: {}', uname, e.message) }

// 2) structural correcto por afiliación viva (prioridad faculty>staff>student>alum)
def correctOid = null;
if (workerLive) correctOid = workerFaculty ? OID_FACULTY : OID_STAFF;
else if (studentLive) correctOid = OID_STUDENT;
else if (alumLive) correctOid = OID_ALUM;

// 3) structural archetype assignments actuales (container-id + oid)
def structAssigns = [];  // [ [id:Long, oid:String], ... ]
user.getAssignment().each { a ->
    def tr = a.getTargetRef();
    if (tr != null && 'ArchetypeType' == tr.getType()?.getLocalPart() && (tr.getOid() in ALL_STRUCT)) {
        structAssigns << [id: a.getId(), oid: tr.getOid()];
    }
};
def currentStructOids = structAssigns.collect { it.oid } as Set;

// 4) decidir target structural
//    - si hay afiliación viva → correctOid
//    - si NO hay afiliación viva pero hay employee structural → conservar employee (evidencia laboral → L=archived)
//    - si NO hay afiliación viva ni employee → conservar el único structural OTHER (researcher/etc.) si existe
if (correctOid == null) {
    if (currentStructOids.contains(OID_FACULTY)) correctOid = OID_FACULTY;
    else if (currentStructOids.contains(OID_STAFF)) correctOid = OID_STAFF;
    else if (currentStructOids.contains(OID_ALUM)) correctOid = OID_ALUM;
    else if (currentStructOids.contains(OID_STUDENT)) correctOid = OID_STUDENT;
    else {
        // solo OTHER_STRUCT (researcher/visitor/...) sin afiliación viva → conservar el primero, sin tocar
        def keep = structAssigns.find { it.oid in OTHER_STRUCT };
        correctOid = keep?.oid;
    }
}

if (correctOid == null) {
    log.info('SANEO: {} ({}) sin structural derivable ni existente — SKIP', uname, uoid);
    return;
}

// 5) ¿ya está saneado? (exactamente 1 structural == correctOid)
def staleAssigns = structAssigns.findAll { it.oid != correctOid };
def hasCorrect = currentStructOids.contains(correctOid);
if (hasCorrect && staleAssigns.isEmpty()) {
    log.debug('SANEO: {} ({}) ya saneado (structural unico {})', uname, uoid, correctOid);
    return;
}

// 6) construir DELTA ATÓMICO: add correcto (si falta) + delete cada stale por container-id
def deltaBuilder = midpoint.prismContext.deltaFor(UserType.class);

// delete stale (por container-id)
staleAssigns.each { sa ->
    def av = new AssignmentType();
    av.setId(sa.id);
    deltaBuilder.item(UserType.F_ASSIGNMENT).delete(av);
};
// add correcto si falta
if (!hasCorrect) {
    def add = new AssignmentType();
    def ref = new ObjectReferenceType();
    ref.setOid(correctOid);
    ref.setType(ArchetypeType.COMPLEX_TYPE);
    add.setTargetRef(ref);
    deltaBuilder.item(UserType.F_ASSIGNMENT).add(add);
}

def delta = deltaBuilder.asObjectDelta(uoid);

// 7) aplicar atómico + reconcile (dispara clockwork → J3/L/D7 sobre objeto con 1 structural)
def opts = com.evolveum.midpoint.schema.ModelExecuteOptions.create().reconcile();
midpoint.executeChanges([delta] as java.util.Collection, opts);

log.info('SANEO OK: {} ({}) -> structural unico {} (stale removidos: {})',
    uname, uoid, correctOid, staleAssigns.collect{it.oid});
